import os
import json
import openai
from flask import Flask, request, jsonify
from vector_database import VectorDatabase  # Assume this is a secure vector database implementation
from input_validation import validate_input  # Assume this is a secure input validation module

app = Flask(__name__)

# Load environment variables for security
OPENAI_API_KEY = os.getenv("OPENAI_API_KEY")
DATABASE_URL = os.getenv("DATABASE_URL")

# Initialize OpenAI API
openai.api_key = OPENAI_API_KEY

# Initialize vector database
vector_db = VectorDatabase(DATABASE_URL)

@app.route('/query', methods=['POST'])
def query():
    user_input = request.json.get('query', '')
    
    # Validate user input
    if not validate_input(user_input):
        return jsonify({"error": "Invalid input"}), 400

    # Retrieve relevant documents from vector database
    relevant_docs = vector_db.retrieve_documents(user_input)

    # Construct the LLM prompt
    prompt = construct_prompt(relevant_docs, user_input)

    # Call the LLM with the prompt
    response = openai.ChatCompletion.create(
        model="gpt-3.5-turbo",
        messages=[{"role": "user", "content": prompt}]
    )

    return jsonify({"response": response['choices'][0]['message']['content']})

def construct_prompt(relevant_docs, user_input):
    context = "\n".join(relevant_docs)
    return f"Context:\n{context}\n\nUser Query:\n{user_input}\n\nResponse:"

if __name__ == '__main__':
    app.run(ssl_context='adhoc')  # Use SSL for secure transport